  // App Interaction State (Splash Screen)
  const [hasStarted, setHasStarted] = useState(false);

  // Auth State
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [staffPassword, setStaffPassword] = useState('cengizbal'); // Default password

  // Admin State
  const [adminTab, setAdminTab] = useState<'menu' | 'social' | 'camera' | 'settings'>('menu');
  const [editingItem, setEditingItem] = useState<MenuItem | null>(null);
  const [showCategoryManager, setShowCategoryManager] = useState(false);

  // Per-language loading states for Edit Modal
  const [translatingStates, setTranslatingStates] = useState<Record<string, boolean>>({});
  const [isTranslatingName, setIsTranslatingName] = useState(false);
  const [isTranslatingAllEdit, setIsTranslatingAllEdit] = useState(false);

  // Categories State with Persistence
  const [categories, setCategories] = useState<string[]>(() => {
    try {
        const saved = localStorage.getItem('categories');
        return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
    } catch {
        return DEFAULT_CATEGORIES;
    }
  });

  useEffect(() => {
    try {
        localStorage.setItem('categories', JSON.stringify(categories));
    } catch (e) {
        // ignore storage errors
    }
  }, [categories]);

  const [newItem, setNewItem] = useState<Partial<MenuItem>>({ category: categories[0] || 'Hauptgang', available: true });
  const [newCategoryName, setNewCategoryName] = useState('');

  // Per-language loading states for Add Item form
