                  <label className="text-slate-400 text-sm block mb-2">Logo Prompt (AI Instructions)</label>
                  <textarea 
                    value={logoPrompt}
                    onChange={(e) => setLogoPrompt(e.target.value)}
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white h-24 text-sm focus:border-blue-500 outline-none resize-none"
                    placeholder="Describe your logo..."
                  />
               </div>

               <div className="flex flex-col sm:flex-row gap-6 items-center sm:items-start bg-slate-950 p-4 rounded-lg">
                   {/* Preview Area */}
                   <div className="flex flex-col items-center gap-2">
                      <span className="text-xs text-slate-500 uppercase font-bold">Preview</span>
                      <div className="w-32 h-32 bg-slate-900 rounded-xl border border-slate-800 flex items-center justify-center relative overflow-hidden shadow-lg">
                          <Logo src={generatedLogoPreview || appLogo} className="w-24 h-24 text-white" />
                          {isGeneratingLogo && (
                             <div className="absolute inset-0 bg-black/60 flex items-center justify-center backdrop-blur-sm z-10">
                                <Loader2 className="animate-spin text-purple-400" size={32} />
                             </div>
                          )}
                      </div>
                      <span className="text-xs text-slate-500">Current / Generated</span>
                   </div>

                   <div className="flex-1 w-full space-y-3 pt-2">
                      <p className="text-sm text-slate-300">
                        Generate a unique logo for your restaurant app using Google's generative AI.
                      </p>

                      <button
                        onClick={handleGenerateLogo}
                        disabled={isGeneratingLogo}
                        className="w-full bg-gradient-to-r from-purple-700 to-indigo-700 hover:from-purple-600 hover:to-indigo-600 text-white py-3 px-4 rounded-lg font-bold transition flex items-center justify-center gap-2 shadow-lg shadow-purple-900/20 disabled:opacity-50"
                      >
                        {isGeneratingLogo ? <Loader2 className="animate-spin" size={20} /> : <Wand2 size={20} />}
                        Generate New Logo
                      </button>

                      {generatedLogoPreview && (
                         <div className="flex gap-3 animate-in slide-in-from-top-2">
                            <button 
                              onClick={handleSaveLogo}
                              className="flex-1 bg-green-700 hover:bg-green-600 text-white py-2 rounded-lg text-sm font-bold transition flex items-center justify-center gap-2"
                            >
                              <CheckCircle size={16} />
                              Apply Logo
                            </button>
                            <button 
                              onClick={handleResetLogo}
                              className="flex-1 bg-slate-700 hover:bg-slate-600 text-white py-2 rounded-lg text-sm font-bold transition flex items-center justify-center gap-2"
                            >
                              <XCircle size={16} />
                              Discard
                            </button>
                         </div>
                      )}
                   </div>
               </div>
            </div>
          </div>

           {/* General Settings */}
           <div className="bg-slate-900 p-6 rounded-xl border border-slate-800">
              <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
                <Settings className="text-slate-400" />
                General Settings
              </h3>
              <div className="space-y-4">
                 <div>
                    <label className="text-slate-400 text-sm block mb-2">Menu Layout</label>
                    <div className="flex bg-slate-800 p-1 rounded-lg w-fit">
                        <button 
                          onClick={() => setMenuLayout('grid')}
                          className={`p-2 rounded-md transition ${menuLayout === 'grid' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                        >
                           <LayoutGrid size={20} />
                        </button>
                        <button 
                          onClick={() => setMenuLayout('list')}
                          className={`p-2 rounded-md transition ${menuLayout === 'list' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                        >
                           <List size={20} />
                        </button>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans selection:bg-[#003399] selection:text-white pb-24">
      {renderHeader()}

      {/* Main Content */}
      <main>
        {userMode === 'staff' ? (
          renderAdminPanel()
        ) : (
          <div className="container mx-auto px-4 py-8 space-y-12">

            {/* Search and Filter */}
             <div className="sticky top-0 z-20 py-2 bg-slate-950/80 backdrop-blur-md">
                <div className="flex gap-2">
                    <div className="relative flex-1">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={20} />
                        <input 
                            type="text" 
                            placeholder={language === 'de' ? 'Suchen...' : 'Search...'}
                            className="w-full bg-slate-900 border border-slate-800 rounded-full py-3 pl-10 pr-4 text-white focus:ring-2 focus:ring-blue-900 outline-none shadow-md"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                    {/* Sort Toggle */}
                     <button 
                         onClick={() => setSortConfig(prev => ({ ...prev, direction: prev.direction === 'asc' ? 'desc' : 'asc' }))}
                         className="bg-slate-900 border border-slate-800 p-3 rounded-full text-slate-400 hover:text-white hover:bg-slate-800"
                     >
                         {sortConfig.direction === 'asc' ? <ArrowDownAZ size={20} /> : <ArrowUpAZ size={20} />}
                     </button>
                </div>
             </div>

            {/* Menu Section */}
            <section id="menu-section" className="space-y-8">
              <div className="flex items-center justify-between">
                <h2 className="text-3xl font-bold text-white brand-font border-l-4 border-[#003399] pl-4">
                  {language === 'de' ? 'Speisekarte' : 
                   language === 'fr' ? 'La Carte' : 
                   language === 'it' ? 'Il Menù' : 
                   language === 'tr' ? 'Menü' : 
                   'Menu'}
                </h2>

                {/* Layout Toggle for Customers */}
                <div className="flex bg-slate-900 p-1 rounded-lg">
                     <button onClick={() => setMenuLayout('grid')} className={`p-1.5 rounded ${menuLayout === 'grid' ? 'bg-slate-700 text-white' : 'text-slate-500'}`}><LayoutGrid size={16}/></button>
                     <button onClick={() => setMenuLayout('list')} className={`p-1.5 rounded ${menuLayout === 'list' ? 'bg-slate-700 text-white' : 'text-slate-500'}`}><List size={16}/></button>
                </div>
              </div>

              {/* Categories */}
              {categories.map(category => {
                const categoryItems = getSortedMenu(displayMenu).filter(item => 
                    item.category === category && 
                    item.name.toLowerCase().includes(searchQuery.toLowerCase())
                );

                if (categoryItems.length === 0) return null;

                return (
                  <div key={category} className="space-y-4 animate-in fade-in duration-500 slide-in-from-bottom-4">
                    <div className="flex items-center gap-4">
                        <div className="h-[1px] bg-slate-800 flex-1"></div>
                        <h3 className="text-xl text-blue-300 font-serif italic">{category}</h3>
                        <div className="h-[1px] bg-slate-800 flex-1"></div>
                    </div>
                    <div className={`grid gap-6 ${menuLayout === 'grid' ? 'grid-cols-1 md:grid-cols-2 lg:grid-cols-3' : 'grid-cols-1 md:grid-cols-2'}`}>
                      {categoryItems.map((item) => (
                        <MenuItemCard 
                          key={item.id} 
                          item={item} 
                          userMode="customer" 
                          language={language}
                          layout={menuLayout}
                          onToggleAvailability={() => {}}
                          onEdit={() => {}}
                          onDelete={() => {}}
                          onUpdate={() => {}}
                          onPromote={() => {}}
                        />
                      ))}
                    </div>
                  </div>
                );
              })}

              {displayMenu.filter(i => i.name.toLowerCase().includes(searchQuery.toLowerCase())).length === 0 && (
                  <div className="text-center py-12 text-slate-500">
                      <Search size={48} className="mx-auto mb-4 opacity-20" />
                      <p>Keine Gerichte gefunden.</p>
                  </div>
              )}
            </section>

            {/* Social Feed Section */}
            <section className="space-y-6 pt-12 border-t border-slate-900">
              <h2 className="text-3xl font-bold text-white brand-font border-l-4 border-pink-600 pl-4">
                {language === 'de' ? 'Neuigkeiten' : 
                 language === 'fr' ? 'Actualités' : 
                 'News'}
              </h2>
              <SocialFeed posts={posts} />
            </section>
          </div>
        )}
      </main>

      {/* Modals & Overlays */}
      <StaffLoginModal 
        isOpen={showLoginModal} 
        onClose={() => setShowLoginModal(false)}
        onLogin={handleLogin}
      />

      {renderEditModal()}

      <ChatBot 
        menu={displayMenu} 
        posts={posts} 
        language={language} 
      />

    </div>
  );
}

