// Sub-component for Menu Item to handle individual animations
interface MenuItemCardProps {
  item: MenuItem;
  userMode: 'customer' | 'staff';
  language: Language;
  layout?: 'grid' | 'list';
  onToggleAvailability: (id: string) => void;
  onEdit: (item: MenuItem) => void;
  onDelete: (id: string) => void;
  onUpdate: (item: MenuItem) => void;
  onPromote: (item: MenuItem) => void;
}

const MenuItemCard: React.FC<MenuItemCardProps> = ({
  item,
  userMode,
  language,
  layout = 'grid',
  onToggleAvailability,
  onEdit,
  onDelete,
  onUpdate,
  onPromote
}) => {
  const [isAnimating, setIsAnimating] = useState(false);
  const [statusEffect, setStatusEffect] = useState<'in' | 'out' | null>(null);
  const [showQuickTranslate, setShowQuickTranslate] = useState(false);
  const [translatingLang, setTranslatingLang] = useState<Language | null>(null);
  const [isTranslatingAllDesc, setIsTranslatingAllDesc] = useState(false);
  const [isTranslatingAll, setIsTranslatingAll] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const prevAvailableRef = useRef(item.available);

  // Monitor availability changes for animation
  useEffect(() => {
    if (prevAvailableRef.current !== item.available) {
      // Trigger animation based on new state
      setStatusEffect(item.available ? 'in' : 'out');

      const timer = setTimeout(() => {
        setStatusEffect(null);
      }, 600);

      prevAvailableRef.current = item.available;
      return () => clearTimeout(timer);
    }
  }, [item.available]);

  const handleClick = () => {
    if (userMode === 'customer') {
      setIsAnimating(true);
      setTimeout(() => setIsAnimating(false), 300);
    }
  };

  const handleTranslationChange = (lang: Language, field: 'name' | 'description', value: string) => {
    const updatedTranslations = {
        ...item.translations,
        [lang]: {
            ...(item.translations?.[lang] || { name: '', description: '' }),
            [field]: value
        }
    };
    onUpdate({ ...item, translations: updatedTranslations });
  };

  const handleQuickAutoTranslate = async (targetLang: Language) => {
     if (targetLang === 'de') return;
     setTranslatingLang(targetLang);
     try {
         const translation = await translateMenuItem(item, targetLang, true);
         // Single atomic update for Quick Translate view
         const updatedTranslations = {
            ...item.translations,
            [targetLang]: {
                name: translation.name,
                description: translation.description
            }
         };
         onUpdate({ ...item, translations: updatedTranslations });
     } catch (e) {
         console.error("Quick translate failed", e);
     } finally {
         setTranslatingLang(null);
     }
  };

  const handleQuickAutoTranslateDescription = async (targetLang: Language) => {
     if (targetLang === 'de') return;
     setTranslatingLang(targetLang);
     try {
         const translation = await translateMenuItem(item, targetLang, true);
         // Single atomic update for Quick Translate Description Only
         const updatedTranslations = {
            ...item.translations,
            [targetLang]: {
                // Preserve existing name if present, otherwise default to empty
                name: item.translations?.[targetLang]?.name || '', 
                description: translation.description
            }
         };
         onUpdate({ ...item, translations: updatedTranslations });
     } catch (e) {
         console.error("Quick translate desc failed", e);
     } finally {
         setTranslatingLang(null);
     }
  };

  const handleTranslateAllDescriptions = async () => {
    setIsTranslatingAllDesc(true);
    const languages: Language[] = ['en', 'fr', 'it', 'tr'];

    // Copy existing translations
    const updatedTranslations = { ...item.translations };

    try {
       // Execute translations in parallel
       const results = await Promise.all(
         languages.map(async (lang) => {
           try {
             const translation = await translateMenuItem(item, lang, true);
             return { lang, description: translation.description };
           } catch (e) {
             console.error(`Error translating ${lang}`, e);
             return null;
           }
         })
       );

       let changed = false;
       results.forEach(res => {
         if (res) {
           updatedTranslations[res.lang] = {
             name: updatedTranslations[res.lang]?.name || '', // Preserve name
             description: res.description
           };
           changed = true;
         }
       });

       if (changed) {
         onUpdate({ ...item, translations: updatedTranslations });
       }

    } catch (e) {
      console.error("Batch translation failed", e);
    } finally {
      setIsTranslatingAllDesc(false);
    }
  };

  const handleTranslateAll = async () => {
    setIsTranslatingAll(true);
    const languages: Language[] = ['en', 'fr', 'it', 'tr'];

    // Copy existing translations
    const updatedTranslations = { ...item.translations };

    try {
       // Execute translations in parallel
       const results = await Promise.all(
         languages.map(async (lang) => {
           try {
             // Translate both name and description
             const translation = await translateMenuItem(item, lang, true);
             return { lang, data: translation };
           } catch (e) {
             console.error(`Error translating ${lang}`, e);
             return null;
           }
         })
       );

       let changed = false;
       results.forEach(res => {
         if (res) {
           updatedTranslations[res.lang] = {
             name: res.data.name,
             description: res.data.description
           };
           changed = true;
         }
       });

       if (changed) {
         onUpdate({ ...item, translations: updatedTranslations });
       }

    } catch (e) {
      console.error("Batch full translation failed", e);
    } finally {
      setIsTranslatingAll(false);
    }
  };

  const handleQuickGenerateImage = async () => {
    setIsGeneratingImage(true);
    try {
        const imageUrl = await generateMenuImage(item.description || item.name);
        if (imageUrl) {
            onUpdate({ ...item, image: imageUrl });
        }
    } catch (e) {
        console.error("Image gen failed", e);
    } finally {
        setIsGeneratingImage(false);
    }
  };

  const handleQuickSelectTranslate = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const lang = e.target.value as Language;
    if (lang && lang !== 'de') {
      handleQuickAutoTranslate(lang);
    }
    // Reset selection
    e.target.value = '';
  };

  const handleQuickSelectTranslateDescription = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const lang = e.target.value as Language;
    if (lang && lang !== 'de') {
      handleQuickAutoTranslateDescription(lang);
    }
    e.target.value = '';
  };

  // Determine dynamic classes based on status effect
  const getStatusClasses = () => {
    if (statusEffect === 'in') return 'ring-2 ring-green-500 bg-green-900/10 scale-[1.02] shadow-[0_0_20px_rgba(34,197,94,0.3)]';
    if (statusEffect === 'out') return 'ring-2 ring-red-500 bg-red-900/10 grayscale';
    if (!item.available) return 'opacity-60 grayscale';
    return '';
  };

  // Layout optimization based on view mode
  const isGrid = layout === 'grid';
  // Grid: always flex-col (image top)
  // List: flex-col on mobile, flex-row on desktop (image left)
  const innerLayoutClass = isGrid ? 'flex-col' : 'flex-col sm:flex-row';
  // Image sizing logic
  const imageContainerClass = isGrid ? 'w-full h-48' : 'w-full sm:w-1/3 h-48 sm:h-auto';

  return (
    <div 
      onClick={handleClick}
      className={`relative flex flex-col bg-slate-900 rounded-xl shadow-md overflow-hidden border border-slate-800 transition-all duration-300 ease-in-out
        ${userMode === 'staff' ? 'hover:scale-[1.02] hover:shadow-xl hover:border-blue-500/30' : 'hover:scale-[1.01] hover:shadow-lg'}
        ${getStatusClasses()}
        ${userMode === 'customer' || userMode === 'staff' ? 'cursor-pointer' : ''} 
        ${isAnimating ? 'scale-105 opacity-60 bg-slate-800' : 'scale-100'}
      `}
    >
      <div className={`flex ${innerLayoutClass} h-full`}>
        {item.image && (
            <div className={`${imageContainerClass} overflow-hidden relative group flex-shrink-0`}>
                <img 
                src={item.image} 
                alt={item.name} 
                className={`w-full h-full object-cover transition-transform duration-500 ${isAnimating ? 'scale-110' : 'hover:scale-105'}`} 
                />
            </div>
        )}
        <div className="p-5 flex-1 flex flex-col justify-between">
            <div>
                <div className="flex justify-between items-start mb-2">
                <h3 className="text-xl font-bold text-slate-100 group-hover:text-blue-300 transition-colors">{item.name}</h3>
                <span className="text-lg font-serif text-blue-400 font-bold whitespace-nowrap ml-2">CHF {item.price.toFixed(2)}</span>
                </div>
                <p className="text-slate-400 italic text-sm mb-4">{item.description}</p>
            </div>

            {userMode === 'staff' && (
                <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-800" onClick={(e) => e.stopPropagation()}>
                    <div className="flex items-center gap-2 flex-wrap">
                         <button 
                            onClick={() => setShowQuickTranslate(!showQuickTranslate)}
                            className={`text-xs flex items-center gap-1 px-2 py-1 rounded transition-colors ${showQuickTranslate ? 'bg-blue-900 text-white' : 'text-slate-500 hover:text-blue-400'}`}
                         >
                            <Globe size={14} />
                            Übersetzungen {showQuickTranslate ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
                         </button>

                         {/* Full Translate */}
                         <div className="relative group">
                             <div className={`flex items-center gap-1 px-2 py-1 rounded transition-colors cursor-pointer border ${translatingLang ? 'bg-purple-900/50 border-purple-500/50 text-white' : 'bg-purple-900/20 hover:bg-purple-900/40 text-purple-300 border-purple-500/30'}`}>
                                {translatingLang && !showQuickTranslate ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                                <span className="text-xs font-semibold">AI Translate</span>
                                <ChevronDown size={12} className="opacity-50" />
                             </div>
                             <select 
                                className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
                                onChange={handleQuickSelectTranslate}
                                value=""
                                disabled={!!translatingLang}
                            >
                                <option value="" disabled>Sprache wählen...</option>
                                <option value="en" className="bg-slate-900">🇬🇧 English</option>
                                <option value="fr" className="bg-slate-900">🇫🇷 Français</option>
                                <option value="it" className="bg-slate-900">🇮🇹 Italiano</option>
                                <option value="tr" className="bg-slate-900">🇹🇷 Türkçe</option>
                            </select>
                         </div>

                         {/* Description Only Translate */}
                         <div className="relative group">
                             <div className={`flex items-center gap-1 px-2 py-1 rounded transition-colors cursor-pointer border ${translatingLang ? 'bg-teal-900/50 border-teal-500/50 text-white' : 'bg-teal-900/20 hover:bg-teal-900/40 text-teal-300 border-teal-500/30'}`}>
                                {translatingLang && !showQuickTranslate ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                                <span className="text-xs font-semibold">AI Desc</span>
                                <ChevronDown size={12} className="opacity-50" />
                             </div>
                             <select 
                                className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
                                onChange={handleQuickSelectTranslateDescription}
                                value=""
                                disabled={!!translatingLang}
                            >
                                <option value="" disabled>Nur Beschreibung...</option>
                                <option value="en" className="bg-slate-900">🇬🇧 English</option>
                                <option value="fr" className="bg-slate-900">🇫🇷 Français</option>
                                <option value="it" className="bg-slate-900">🇮🇹 Italiano</option>
                                <option value="tr" className="bg-slate-900">🇹🇷 Türkçe</option>
                            </select>
                         </div>

                         {/* All Descriptions Translate Button */}
                         <button 
                            onClick={handleTranslateAllDescriptions}
                            disabled={isTranslatingAllDesc || !!translatingLang}
                            className={`flex items-center gap-1 px-2 py-1 rounded transition-colors border ${isTranslatingAllDesc ? 'bg-indigo-900/50 border-indigo-500/50 text-white' : 'bg-indigo-900/20 hover:bg-indigo-900/40 text-indigo-300 border-indigo-500/30'}`}
                            title="Alle Beschreibungen automatisch übersetzen (EN, FR, IT, TR)"
                         >
                            {isTranslatingAllDesc ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                            <span className="text-xs font-semibold">All Descs</span>
                         </button>

                         {/* All (Name+Desc) Translate Button */}
                         <button 
                            onClick={handleTranslateAll}
                            disabled={isTranslatingAll || !!translatingLang}
                            className={`flex items-center gap-1 px-2 py-1 rounded transition-colors border ${isTranslatingAll ? 'bg-orange-900/50 border-orange-500/50 text-white' : 'bg-orange-900/20 hover:bg-orange-900/40 text-orange-300 border-orange-500/30'}`}
                            title="Alles automatisch übersetzen (Name + Beschreibung für EN, FR, IT, TR)"
                         >
                            {isTranslatingAll ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                            <span className="text-xs font-semibold">Full Auto</span>
                         </button>
                    </div>

                    <div className="flex items-center gap-2 mt-2 md:mt-0">
                        <button 
                            onClick={handleQuickGenerateImage} 
                            disabled={isGeneratingImage}
                            className={`p-2 rounded-full transition-colors ${isGeneratingImage ? 'bg-cyan-900/50 text-cyan-200' : 'bg-slate-800 text-cyan-400 hover:bg-cyan-900/50 hover:text-cyan-300'}`}
                            title="Bild mit KI generieren"
                        >
                            {isGeneratingImage ? <Loader2 size={18} className="animate-spin" /> : <Wand2 size={18} />}
                        </button>
                        <button onClick={() => onPromote(item)} className="p-2 rounded-full bg-slate-800 text-pink-400 hover:bg-pink-900/50 hover:text-pink-300" title="Create AI Promo Post">
                            <Megaphone size={18} />
                        </button>
                        <button onClick={() => onToggleAvailability(item.id)} className={`p-2 rounded-full transition-all ${item.available ? 'bg-green-900/50 text-green-400 hover:bg-green-900' : 'bg-red-900/50 text-red-400 hover:bg-red-900'}`} title={item.available ? "Als ausverkauft markieren" : "Als verfügbar markieren"}>
                            {item.available ? <CheckCircle size={18} /> : <XCircle size={18} />}
                        </button>
                        <button onClick={() => onEdit(item)} className="p-2 rounded-full bg-slate-800 text-blue-400 hover:bg-blue-900/50 hover:text-blue-300" title="Bearbeiten">
                            <Edit2 size={18} />
                        </button>
                        <button onClick={() => onDelete(item.id)} className="p-2 rounded-full bg-slate-800 text-slate-400 hover:bg-red-900/50 hover:text-red-400" title="Löschen">
                            <Trash2 size={18} />
                        </button>
                    </div>
                </div>
            )}
        </div>
      </div>

      {/* Quick Translation Inline Panel */}
      {userMode === 'staff' && showQuickTranslate && (
         <div className="bg-slate-950 p-4 border-t border-slate-800 animate-in slide-in-from-top-2 duration-200" onClick={(e) => e.stopPropagation()}>
             <h4 className="text-xs font-bold text-slate-400 mb-3 uppercase tracking-wider">Alle Übersetzungen</h4>
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                 {(['en', 'fr', 'it', 'tr'] as Language[]).map(lang => (
                     <div key={lang} className="bg-slate-900/50 p-3 rounded-lg border border-slate-800">
                         <div className="flex justify-between items-center mb-2">
                             <div className="flex items-center gap-2">
                                 <span className="text-xs font-bold text-blue-300 uppercase">{lang}</span>
                             </div>
                             <button 
                                onClick={() => handleQuickAutoTranslate(lang)}
                                disabled={translatingLang === lang}
                                className="text-[10px] bg-purple-600 hover:bg-purple-700 text-white px-2 py-0.5 rounded flex items-center gap-1 transition disabled:opacity-50"
                                title="Automatisch mit AI übersetzen"
                             >
                                {translatingLang === lang ? <Loader2 size={10} className="animate-spin" /> : <Sparkles size={10} />}
                                Auto
                             </button>
                         </div>
                         <div className="space-y-2">
                             <input 
                                 type="text" 
                                 value={item.translations?.[lang]?.name || ''}
                                 onChange={(e) => handleTranslationChange(lang, 'name', e.target.value)}
                                 className="w-full bg-slate-800 border border-slate-700 rounded px-2 py-1 text-xs text-white focus:border-blue-500 outline-none"
                                 placeholder={`Name (${lang.toUpperCase()})`}
                             />
                             <textarea 
                                 value={item.translations?.[lang]?.description || ''}
                                 onChange={(e) => handleTranslationChange(lang, 'description', e.target.value)}
                                 className="w-full bg-slate-800 border border-slate-700 rounded px-2 py-1 text-xs text-white focus:border-blue-500 outline-none resize-none h-16"
                                 placeholder={`Beschreibung (${lang.toUpperCase()})`}
                             />
                         </div>
                     </div>
                 ))}
             </div>
         </div>
      )}

      {/* Sold out badge for everyone */}
      {!item.available && (
        <div className={`absolute top-2 right-2 bg-red-600 text-white text-xs font-bold px-2 py-1 rounded shadow-lg transition-opacity duration-300 ${statusEffect === 'out' ? 'animate-in zoom-in' : ''}`}>
            AUSVERKAUFT
        </div>
      )}
    </div>
  );
};

export default function App() {
  const [userMode, setUserMode] = useState<'customer' | 'staff'>('customer');
  const [language, setLanguage] = useState<Language>('de');
  const [menu, setMenu] = useState<MenuItem[]>(INITIAL_MENU);
  const [posts, setPosts] = useState<SocialPost[]>(INITIAL_POSTS);

  // App Interaction State (Splash Screen)
  const [hasStarted, setHasStarted] = useState(false);

  // Auth State
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [staffPassword, setStaffPassword] = useState('cengizbal'); // Default password

  // Admin State
  const [adminTab, setAdminTab] = useState<'menu' | 'reservations' | 'social' | 'camera' | 'settings'>('menu');
  const [editingItem, setEditingItem] = useState<MenuItem | null>(null);
  const [showCategoryManager, setShowCategoryManager] = useState(false);

  // Reservations State
  const [reservations, setReservations] = useState<Reservation[]>(() => {
    try {
        const saved = localStorage.getItem('reservations');
        return saved ? JSON.parse(saved) : [];
    } catch {
        return [];
    }
  });

  const [newReservation, setNewReservation] = useState<Partial<Reservation>>({
      guests: 2,
      date: new Date().toISOString().split('T')[0],
      time: '19:00',
      name: '',
      phone: '',
      notes: ''
  });

  useEffect(() => {
    try {
        localStorage.setItem('reservations', JSON.stringify(reservations));
    } catch (e) {
        // ignore
    }
  }, [reservations]);

  // Per-language loading states for Edit Modal
  const [translatingStates, setTranslatingStates] = useState<Record<string, boolean>>({});
  const [isTranslatingName, setIsTranslatingName] = useState(false);
  const [isTranslatingAllEdit, setIsTranslatingAllEdit] = useState(false);

  // Categories State with Persistence
  const [categories, setCategories] = useState<string[]>(() => {
    try {
        const saved = localStorage.getItem('categories');
        return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
    } catch {
        return DEFAULT_CATEGORIES;
    }
  });

  useEffect(() => {
    try {
        localStorage.setItem('categories', JSON.stringify(categories));
    } catch (e) {
        // ignore storage errors
    }
  }, [categories]);

  const [newItem, setNewItem] = useState<Partial<MenuItem>>({ category: categories[0] || 'Hauptgang', available: true });
  const [newCategoryName, setNewCategoryName] = useState('');

  // Per-language loading states for Add Item form
  const [newItemTranslatingStates, setNewItemTranslatingStates] = useState<Record<string, boolean>>({});

  // Batch Translation State
  const [isBatchTranslating, setIsBatchTranslating] = useState<string | null>(null);

  // Image Generation States
  const [isGeneratingNewImage, setIsGeneratingNewImage] = useState(false);
  const [isGeneratingEditImage, setIsGeneratingEditImage] = useState(false);

  // Logo Generation State
  const [appLogo, setAppLogo] = useState<string | null>(() => {
    try {
        return localStorage.getItem('appLogo');
    } catch {
        return null;
    }
  });
  const [logoPrompt, setLogoPrompt] = useState("Logo for Rheinhafen Restaurant. Centered maritime icon with anchor and ship wheel. Text 'RHEIN' on left, 'HAFEN' on right, 'RESTAURANT' at bottom. Professional, vector graphic style, minimal, deep royal blue and white colors, clear and visually appealing.");
  const [isGeneratingLogo, setIsGeneratingLogo] = useState(false);
  const [generatedLogoPreview, setGeneratedLogoPreview] = useState<string | null>(null);

  useEffect(() => {
    try {
        if (appLogo) {
            localStorage.setItem('appLogo', appLogo);
        } else {
            localStorage.removeItem('appLogo');
        }
    } catch (e) {
        // ignore storage errors
    }
  }, [appLogo]);

  const [menuLayout, setMenuLayout] = useState<'grid' | 'list'>(() => {
    try {
        return (localStorage.getItem('menuLayout') as 'grid' | 'list') || 'grid';
    } catch {
        return 'grid';
    }
  });

  useEffect(() => {
    try {
        localStorage.setItem('menuLayout', menuLayout);
    } catch (e) {
        // ignore storage errors
    }
  }, [menuLayout]);

  const [searchQuery, setSearchQuery] = useState('');

  // Sorting State
  const [sortConfig, setSortConfig] = useState<{
    key: 'name' | 'price' | 'category',
    direction: 'asc' | 'desc'
  }>(() => {
    try {
        const saved = localStorage.getItem('sortConfig');
        return saved ? JSON.parse(saved) : { key: 'name', direction: 'asc' };
    } catch {
        return { key: 'name', direction: 'asc' };
    }
  });

  useEffect(() => {
    try {
        localStorage.setItem('sortConfig', JSON.stringify(sortConfig));
    } catch (e) {
        // ignore storage errors
    }
  }, [sortConfig]);

  const [newPostContent, setNewPostContent] = useState('');
  const [selectedPlatform, setSelectedPlatform] = useState<'instagram' | 'facebook' | 'tiktok'>('instagram');
  const [newPostImage, setNewPostImage] = useState<string | null>(null);

  // Camera State - Persist to localStorage
  const [cameraUrl, setCameraUrl] = useState(() => {
    try {
      return localStorage.getItem('cameraUrl') || '';
    } catch (e) {
      console.warn("LocalStorage access failed", e);
      return '';
    }
  });

  useEffect(() => {
    try {
      localStorage.setItem('cameraUrl', cameraUrl);
    } catch (e) {
      console.warn("LocalStorage write failed", e);
    }
  }, [cameraUrl]);

  const [isCameraConnected, setIsCameraConnected] = useState(false);
  const [cameraError, setCameraError] = useState<string | null>(null);

  // --- Sorting Logic ---
  const getSortedMenu = (items: MenuItem[]) => {
    return [...items].sort((a, b) => {
        let aValue: string | number = '';
        let bValue: string | number = '';

        switch (sortConfig.key) {
            case 'name':
                aValue = a.name.toLowerCase();
                bValue = b.name.toLowerCase();
                break;
            case 'price':
                aValue = a.price;
                bValue = b.price;
                break;
            case 'category':
                aValue = a.category;
                bValue = b.category;
                break;
        }

        if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
        if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
    });
  };

  // --- Category Logic ---
  const handleAddCategory = () => {
    const name = newCategoryName.trim();
    if (name && !categories.includes(name)) {
        setCategories([...categories, name]);
        setNewCategoryName('');
    }
  };

  const handleDeleteCategory = (categoryName: string) => {
    const hasItems = menu.some(item => item.category === categoryName);
    if (hasItems) {
        alert("Kategorie kann nicht gelöscht werden, da sie noch Artikel enthält. Bitte verschieben oder löschen Sie diese zuerst.");
        return;
    }
    if (confirm(`Kategorie "${categoryName}" wirklich löschen?`)) {
        setCategories(categories.filter(c => c !== categoryName));
    }
  };

  const handleUpdateCategory = (oldName: string, newName: string) => {
    if (!newName.trim() || categories.includes(newName.trim())) return;

    // Update category list
    setCategories(categories.map(c => c === oldName ? newName.trim() : c));

    // Update items assigned to this category
    setMenu(menu.map(item => item.category === oldName ? { ...item, category: newName.trim() } : item));
  };

  // --- Translation Logic ---
  const [displayMenu, setDisplayMenu] = useState<MenuItem[]>(menu);

  useEffect(() => {
    const translateAll = async () => {
      if (language === 'de') {
        setDisplayMenu(menu);
        return;
      }

      const translatedItems = await Promise.all(
        menu.map(async (item) => {
          // Note: We process all items regardless of availability so filtering happens at render
          const translated = await translateMenuItem(item, language);
          return {
            ...item,
            name: translated.name,
            description: translated.description
          };
        })
      );

      // Filter nulls (safeguard)
      setDisplayMenu(translatedItems.filter((i): i is MenuItem => i !== null));
    };

    translateAll();
  }, [language, menu, userMode]);

  // --- Auth Handlers ---
  const handleUserModeChange = (mode: 'customer' | 'staff') => {
    if (mode === 'staff') {
      if (isAuthenticated) {
        setUserMode('staff');
      } else {
        setShowLoginModal(true);
      }
    } else {
      setUserMode('customer');
    }
  };

  const handleLogin = (password: string) => {
    if (password === staffPassword) {
      setIsAuthenticated(true);
      setUserMode('staff');
      setShowLoginModal(false);
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserMode('customer');
  };

  // --- Staff Actions ---

  const handleAddItem = () => {
    if (!newItem.name || !newItem.price) return;
    const item: MenuItem = {
      id: Date.now().toString(),
      name: newItem.name,
      description: newItem.description || '',
      price: Number(newItem.price),
      category: newItem.category || categories[0] || 'Hauptgang',
      available: newItem.available ?? true,
      image: newItem.image || `https://picsum.photos/400/300?random=${Math.floor(Math.random() * 100)}`,
      translations: newItem.translations
    };
    setMenu([...menu, item]);
    setNewItem({ category: categories[0] || 'Hauptgang', available: true, name: '', description: '', price: 0, image: '', translations: {} });
  };

  const handleUpdateItem = () => {
    if (!editingItem) return;
    setMenu(menu.map(m => m.id === editingItem.id ? editingItem : m));
    setEditingItem(null);
  };

  // Updates menu item from inline edits (quick translation)
  const handleInlineUpdate = (updatedItem: MenuItem) => {
    setMenu(menu.map(m => m.id === updatedItem.id ? updatedItem : m));
  };

  const handleDeleteItem = (id: string) => {
    setMenu(menu.filter(m => m.id !== id));
  };

  const toggleAvailability = (id: string) => {
    setMenu(menu.map(m => m.id === id ? { ...m, available: !m.available } : m));
  };

  const handleEditClick = (item: MenuItem) => {
    setEditingItem(item);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewPostImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMenuImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewItem({ ...newItem, image: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleEditItemImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editingItem) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditingItem({ ...editingItem, image: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerateNewItemImage = async () => {
    if (!newItem.description && !newItem.name) return;
    setIsGeneratingNewImage(true);
    try {
        const generatedImage = await generateMenuImage(newItem.description || newItem.name || '');
        if (generatedImage) {
            setNewItem(prev => ({ ...prev, image: generatedImage }));
        }
    } catch (e) {
        console.error("Failed to generate image", e);
    } finally {
        setIsGeneratingNewImage(false);
    }
  };

  const handleGenerateEditItemImage = async () => {
    if (!editingItem || (!editingItem.description && !editingItem.name)) return;
    setIsGeneratingEditImage(true);
    try {
        const generatedImage = await generateMenuImage(editingItem.description || editingItem.name || '');
        if (generatedImage) {
            setEditingItem(prev => prev ? ({ ...prev, image: generatedImage }) : null);
        }
    } catch (e) {
        console.error("Failed to generate image", e);
    } finally {
        setIsGeneratingEditImage(false);
    }
  };

  const handleGenerateLogo = async () => {
    if (!logoPrompt) return;
    setIsGeneratingLogo(true);
    try {
      const logoUrl = await generateLogo(logoPrompt);
      if (logoUrl) {
        setGeneratedLogoPreview(logoUrl);
      }
    } catch (e) {
      console.error("Failed to generate logo", e);
    } finally {
      setIsGeneratingLogo(false);
    }
  };

  const handleSaveLogo = () => {
    if (generatedLogoPreview) {
      setAppLogo(generatedLogoPreview);
    }
  };

  const handleResetLogo = () => {
    setAppLogo(null);
    setGeneratedLogoPreview(null);
  };

  // Helper to update translations safely
  const handleTranslationUpdate = (lang: Language, field: 'name' | 'description', value: string) => {
    if (!editingItem) return;

    setEditingItem({
        ...editingItem,
        translations: {
            ...editingItem.translations,
            [lang]: {
                ...(editingItem.translations?.[lang] || { name: '', description: '' }),
                [field]: value
            }
        }
    });
  };

  const handleNewItemTranslationUpdate = (lang: Language, field: 'name' | 'description', value: string) => {
    setNewItem({
        ...newItem,
        translations: {
            ...newItem.translations,
            [lang]: {
                ...(newItem.translations?.[lang] || { name: '', description: '' }),
                [field]: value
            }
        }
    });
  };

  // Refactored to allow targeting specific language with parallel loading states
  const handleSpecificAutoTranslate = async (targetLang: Language) => {
    if (!editingItem) return;

    setTranslatingStates(prev => ({ ...prev, [targetLang]: true }));
    try {
        // Force refresh to ignore existing partial translations or cache
        const translation = await translateMenuItem(editingItem, targetLang, true);

        // Single atomic update
        setEditingItem(prev => {
            if (!prev) return null;
            return {
                ...prev,
                translations: {
                    ...prev.translations,
                    [targetLang]: {
                        ...(prev.translations?.[targetLang] || { name: '', description: '' }),
                        name: translation.name,
                        description: translation.description
                    }
                }
            };
        });
    } catch (error) {
        console.error("Translation failed", error);
    } finally {
        setTranslatingStates(prev => ({ ...prev, [targetLang]: false }));
    }
  };

  const handleAutoTranslateAllLanguagesEdit = async () => {
    if (!editingItem) return;
    setIsTranslatingAllEdit(true);
    const languages: Language[] = ['en', 'fr', 'it', 'tr'];

    try {
        const results = await Promise.all(
            languages.map(lang => translateMenuItem(editingItem, lang, true))
        );

        setEditingItem(prev => {
            if (!prev) return null;
            const updatedTranslations = { ...prev.translations };
            languages.forEach((lang, index) => {
                updatedTranslations[lang] = results[index];
            });
            return { ...prev, translations: updatedTranslations };
        });
    } catch (e) {
        console.error("Batch translation failed", e);
    } finally {
        setIsTranslatingAllEdit(false);
    }
  };

  const handleNewItemAutoTranslate = async (targetLangOverride?: Language) => {
    const target = targetLangOverride;
    if (!newItem.name || !target || target === 'de') return;

    setNewItemTranslatingStates(prev => ({ ...prev, [target]: true }));
    try {
        const tempItem: MenuItem = {
            id: 'temp',
            name: newItem.name,
            description: newItem.description || '',
            price: newItem.price || 0,
            category: newItem.category || categories[0],
            available: true
        };

        const translation = await translateMenuItem(tempItem, target, true);

        // Single atomic update
        setNewItem(prev => ({
            ...prev,
            translations: {
                ...prev.translations,
                [target]: {
                    ...(prev.translations?.[target] || { name: '', description: '' }),
                    name: translation.name,
                    description: translation.description
                }
            }
        }));
    } catch (error) {
        console.error("Translation failed", error);
    } finally {
        setNewItemTranslatingStates(prev => ({ ...prev, [target]: false }));
    }
  };

  const handleTranslateNameAll = async (target: 'new' | 'edit') => {
    const sourceItem = target === 'new' ? newItem : editingItem;
    if (!sourceItem || !sourceItem.name) return;

    setIsTranslatingName(true);
    const languages: Language[] = ['en', 'fr', 'it', 'tr'];

    try {
        const results = await Promise.all(
            languages.map(async (lang) => {
                // Create a temp item with available context. 
                // We use description if present to help the AI context, 
                // but we only extract and use the name from the result.
                const tempItem = { 
                    ...sourceItem, 
                    id: 'temp', 
                    price: sourceItem.price || 0, 
                    category: sourceItem.category || categories[0], 
                    available: true,
                    description: sourceItem.description || '' 
                } as MenuItem;

                const translation = await translateMenuItem(tempItem, lang, true);
                return { lang, name: translation.name };
            })
        );

        if (target === 'new') {
            setNewItem(prev => {
                const newTranslations = { ...prev.translations };
                results.forEach(res => {
                    newTranslations[res.lang] = {
                        ...(newTranslations[res.lang] || { name: '', description: '' }),
                        name: res.name
                    };
                });
                return { ...prev, translations: newTranslations };
            });
        } else {
             setEditingItem(prev => {
                if (!prev) return null;
                const newTranslations = { ...prev.translations };
                results.forEach(res => {
                    newTranslations[res.lang] = {
                        ...(newTranslations[res.lang] || { name: '', description: '' }),
                        name: res.name
                    };
                });
                return { ...prev, translations: newTranslations };
            });
        }

    } catch (e) {
        console.error("Name batch translation failed", e);
    } finally {
        setIsTranslatingName(false);
    }
  };

  const handleBatchTranslateAll = async (targetLang: Language) => {
    if (targetLang === 'de') return;

    setIsBatchTranslating(targetLang);
    try {
        const updatedMenu = await Promise.all(
            menu.map(async (item) => {
                try {
                    const translation = await translateMenuItem(item, targetLang, true);
                    return {
                        ...item,
                        translations: {
                            ...item.translations,
                            [targetLang]: {
                                name: translation.name,
                                description: translation.description
                            }
                        }
