                          userMode="customer" 
                          language={language}
                          layout={menuLayout}
                          onToggleAvailability={() => {}}
                          onEdit={() => {}}
                          onDelete={() => {}}
                          onUpdate={() => {}}
                          onPromote={() => {}}
                        />
                      ))}
                    </div>
                  </div>
                );
              })}

              {displayMenu.filter(i => i.name.toLowerCase().includes(searchQuery.toLowerCase())).length === 0 && (
                  <div className="text-center py-12 text-slate-500">
                      <Search size={48} className="mx-auto mb-4 opacity-20" />
                      <p>Keine Gerichte gefunden.</p>
                  </div>
              )}
            </section>

            {/* Social Feed Section */}
            <section className="space-y-6 pt-12 border-t border-slate-900">
              <h2 className="text-3xl font-bold text-white brand-font border-l-4 border-pink-600 pl-4">
                {language === 'de' ? 'Neuigkeiten' : 
                 language === 'fr' ? 'Actualités' : 
                 'News'}
              </h2>
              <SocialFeed posts={posts} />
            </section>
          </div>
        )}
      </main>

      {/* Modals & Overlays */}
      <StaffLoginModal 
        isOpen={showLoginModal} 
        onClose={() => setShowLoginModal(false)}
        onLogin={handleLogin}
      />

      {renderEditModal()}

      <ChatBot 
        menu={displayMenu} 
        posts={posts} 
        language={language} 
      />

    </div>
  );
}

