async function decodeAudioData(audioData: ArrayBuffer, sampleRate: number = 24000): Promise<AudioBuffer> {
  const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate });
  const dataView = new DataView(audioData);
  const numChannels = 1;
  const numSamples = audioData.byteLength / 2;
  const buffer = audioContext.createBuffer(numChannels, numSamples, sampleRate);
  const channelData = buffer.getChannelData(0);
  for (let i = 0; i < numSamples; i++) {
     const int16 = dataView.getInt16(i * 2, true);
     channelData[i] = int16 / 32768.0;
  }
  return buffer;
}

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

